import{_ as s,C as d,o as h,c as m,j as e,a,E as r,w as o,a1 as i}from"./chunks/framework.BX4nIuL2.js";const k=JSON.parse('{"title":"SLA design guide","description":"","frontmatter":{},"headers":[],"relativePath":"courses/fab-course/doc/3_3dprinter/6.sladesignguide.md","filePath":"courses/fab-course/doc/3_3dprinter/6.sladesignguide.md"}'),u={name:"courses/fab-course/doc/3_3dprinter/6.sladesignguide.md"},g={href:"https://www.3dhubs.com/knowledge-base/how-design-parts-sla-3D-printing",target:"_blank",rel:"noreferrer"};function b(p,t,c,f,_,O){const l=d("center"),n=d("font");return h(),m("div",null,[t[3]||(t[3]=e("h1",{id:"sla-design-guide",tabindex:"-1"},[a("SLA design guide "),e("a",{class:"header-anchor",href:"#sla-design-guide","aria-label":'Permalink to "SLA design guide"'},"​")],-1)),t[4]||(t[4]=e("h2",{id:"_1-general",tabindex:"-1"},[a("1. General "),e("a",{class:"header-anchor",href:"#_1-general","aria-label":'Permalink to "1. General"'},"​")],-1)),e("p",null,[t[1]||(t[1]=e("img",{src:"https://github.com/bobwu0214/dm360.github.io/raw/master/Img/3dhubssladesignguide.png",alt:""},null,-1)),e("a",g,[r(l,null,{default:o(()=>[...t[0]||(t[0]=[a("reference design guide from 3dhubs",-1)])]),_:1})])]),t[5]||(t[5]=i('<h2 id="_2-wall-thickness" tabindex="-1">2. Wall thickness <a class="header-anchor" href="#_2-wall-thickness" aria-label="Permalink to &quot;2. Wall thickness&quot;">​</a></h2><p><img src="https://github.com/bobwu0214/dm360.github.io/raw/master/Img/wallthickness.png" alt=""></p><table tabindex="0"><thead><tr><th>requirement</th><th>parameter(mm)</th></tr></thead><tbody><tr><td>keep strength</td><td>&gt;2.0</td></tr><tr><td>keep the appearance</td><td>&gt;0.8</td></tr><tr><td>the minimum  thickness</td><td>&gt;0.4</td></tr><tr><td>There are different thickness walls. After checking the appearance and strength. Designer should make sure the thickness bigger than the above parameter or the model might have risk.</td><td></td></tr></tbody></table><h2 id="_3-column" tabindex="-1">3. Column <a class="header-anchor" href="#_3-column" aria-label="Permalink to &quot;3. Column&quot;">​</a></h2><p><img src="https://github.com/bobwu0214/dm360.github.io/raw/master/Img/pole.png" alt=""> We need at least following parameter to keep enough strength:</p><ul><li>The diameter of round column at least 2.5mm;</li><li>The size of square column at least 3mm*3mm</li></ul><p>If the parameter less than the above parameter, the model may failure:</p><ul><li>For blue part in the above picture <ul><li>Scraper may broke the model before solidify the next layer of model;</li><li>The vibration of ultrasonic cleaning machine may broken the model;</li><li>Some small accident during transport may broken the model;</li></ul></li><li>For yellow part in the above picture: The model would bend because of outside environment;</li></ul><h2 id="_4-hole" tabindex="-1">4. Hole <a class="header-anchor" href="#_4-hole" aria-label="Permalink to &quot;4. Hole&quot;">​</a></h2><p><img src="https://github.com/bobwu0214/dm360.github.io/raw/master/Img/hole.png" alt=""></p><ul><li>The diameter of round hole should be at least 1.2mm, or the hole may close off;</li><li>The size of square hole should be at least 1mm, or the hole may close off.</li></ul><p>In addition, the 3D printing hole would be a little small than design. If designer has requirement in size, engineer and designer can use machine to enlarge it.</p><h2 id="_5-text" tabindex="-1">5. Text <a class="header-anchor" href="#_5-text" aria-label="Permalink to &quot;5. Text&quot;">​</a></h2><p><img src="https://github.com/bobwu0214/dm360.github.io/raw/master/Img/hole.png" alt=""> The laser of SLA machine has minimum laser spot size. So the heigh of model need safety value( the minimum text height )</p><p>| Limit value(mm) | Safety value(mm) | | --- | --- | --- | | Embossed text | 3 | 4 | | Engraved text | 2.5 | 4 |</p><h2 id="_6-bridge" tabindex="-1">6. Bridge <a class="header-anchor" href="#_6-bridge" aria-label="Permalink to &quot;6. Bridge&quot;">​</a></h2><p><img src="https://github.com/bobwu0214/dm360.github.io/raw/master/Img/WechatIMG833.jpeg" alt=""></p><p>The safety value should be less than 8mm, or we need support for bridge</p><h2 id="_7-overhang-angle" tabindex="-1">7. Overhang angle <a class="header-anchor" href="#_7-overhang-angle" aria-label="Permalink to &quot;7. Overhang angle&quot;">​</a></h2><p><img src="https://github.com/bobwu0214/dm360.github.io/raw/master/Img/slaoverhang.png" alt=""></p><p>Normal ,the overhang angle over 40 in model should add support, but we don&#39;t need support in this model because it is short and thick</p><h2 id="_8-cone" tabindex="-1">8. Cone <a class="header-anchor" href="#_8-cone" aria-label="Permalink to &quot;8. Cone&quot;">​</a></h2><p><img src="https://github.com/bobwu0214/dm360.github.io/raw/master/Img/cone.png" alt=""></p>',23)),r(n,{color:"red",size:"30"},{default:o(()=>[...t[2]||(t[2]=[a("I need support to measure it ",-1)])]),_:1}),t[6]||(t[6]=i('<h2 id="_9-circle" tabindex="-1">9. Circle <a class="header-anchor" href="#_9-circle" aria-label="Permalink to &quot;9. Circle&quot;">​</a></h2><p>In prototype measure, almost every direction would scale for 99%.</p><p><img src="https://github.com/bobwu0214/dm360.github.io/raw/master/Img/slacone.png" alt=""></p><h2 id="_10-groove" tabindex="-1">10. Groove <a class="header-anchor" href="#_10-groove" aria-label="Permalink to &quot;10. Groove&quot;">​</a></h2><p><img src="https://github.com/bobwu0214/dm360.github.io/raw/master/Img/groovedesjgn.png" alt=""></p><p><img src="https://github.com/bobwu0214/dm360.github.io/raw/master/Img/WechatIMG838.jpeg" alt=""></p><table tabindex="0"><thead><tr><th>Width\\Thickness</th><th>0.2</th><th>0.4</th><th>0.8</th><th>1.0</th></tr></thead><tbody><tr><td>1.0</td><td>OK</td><td>OK</td><td>OK</td><td>OK</td></tr><tr><td>0.9</td><td>OK</td><td>OK</td><td>OK</td><td>OK</td></tr><tr><td>0.8</td><td>OK</td><td>OK</td><td>OK</td><td>OK</td></tr><tr><td>0.7</td><td>OK</td><td>OK</td><td>OK</td><td>OK</td></tr><tr><td>0.6</td><td>OK</td><td>OK</td><td>OK</td><td>OK</td></tr><tr><td>0.5</td><td>OK</td><td>OK</td><td>OK</td><td>OK</td></tr><tr><td>0.4</td><td>OK</td><td>OK</td><td>OK</td><td>OK</td></tr><tr><td>0.3</td><td>OK</td><td>OK</td><td>OK</td><td>OK</td></tr><tr><td>0.2</td><td>NO</td><td>NO</td><td>NO</td><td>NO</td></tr><tr><td>0.1</td><td>NO</td><td>NO</td><td>NO</td><td>NO</td></tr><tr><td>The conclusion is width bigger than 0.3mm, thickness bigger than0.2mm.</td><td></td><td></td><td></td><td></td></tr></tbody></table>',7))])}const K=s(u,[["render",b]]);export{k as __pageData,K as default};
